  ('pukao-0c700c30-moex-00247', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '假設一理性消費者僅消費X與Y兩種產品，若他覺得(X,Y)=(1,1)、(X,Y)=(2,1)、(X,Y)=(1,2)三個消 a a b b c c 費組合帶給他的滿足程度相同，請問下列何者可代表此消費者之效用函數？', '["U(X,Y)=1.5X+1.5Y", "U(X,Y)=X+Y", "U(X,Y)=Min{X,Y}", "U(X,Y)=XY"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00248', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '所謂名目匯率是指：', '["一種追求一國絕對利益的成本", "一種用另一國通貨表示一國通貨的價格", "一種以進口物品表示出口物品的比率", "一種追求一國比較利益的成本"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
